function fetchData() {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      const success = true; // change to false to test rejection
      if (success) {
        resolve('Data fetched!');
      } else {
        reject('Error fetching data');
      }
    }, 1000);
  });
}

fetchData()
  .then(data => console.log(data))
  .catch(err => console.error(err));
